+
+    #[test]
+    fn timing_counter_records_single_observation() {
+        let counter = TimingCounter::new();
+        counter.record(500);
+        let snap = counter.snapshot();
+        assert_eq!(snap.count, 1);
+        assert_eq!(snap.total_us, 500);
+        assert_eq!(snap.max_us, 500);
+        assert_eq!(snap.avg_us, 500);
