+
+    let err = store
+        .validate_integrity()
+        .expect_err("checksum mismatch should be detected");
+    assert!(
+        err.to_string().contains("checksum mismatch"),
+        "unexpected error: {err}"
+    );
+
+    Ok(())
+}
